CREATE USER [synps-ws-neo-tracker] FROM EXTERNAL PROVIDER;
GO

ALTER ROLE db_owner ADD MEMBER [synps-ws-neo-tracker];
GO

---

SELECT name, type_desc, authentication_type_desc
FROM sys.database_principals
WHERE name = 'synps-ws-neo-tracker';


SELECT TOP 5 *
FROM OPENROWSET(
    BULK 'source/daily/neo_2026-06-21.json',
    DATA_SOURCE = 'cosmictracker_storage',
    SINGLE_CLOB
) AS doc;

SELECT name, location FROM sys.external_data_sources;

SELECT TOP 1 BulkColumn
FROM OPENROWSET(
    BULK 'source/daily/neo_2026-06-20.json',
    DATA_SOURCE = 'cosmictracker_storage',
    SINGLE_CLOB
) AS doc;

SELECT name, location
FROM sys.external_data_sources;

SELECT *
FROM sys.database_scoped_credentials;

SELECT *
FROM OPENROWSET(
    BULK 'source/daily/*.json',
    DATA_SOURCE = 'cosmictracker_storage',
    FORMAT = 'CSV',
    FIELDTERMINATOR = '0x0b',
    FIELDQUOTE = '0x0b'
)
WITH (
    jsonContent VARCHAR(MAX)
) AS rows;


SELECT TOP 1 LEFT(jsonContent, 500)
FROM OPENROWSET(
    BULK 'source/daily/*.json',
    DATA_SOURCE = 'cosmictracker_storage',
    FORMAT = 'CSV',
    FIELDTERMINATOR = '0x0b',
    FIELDQUOTE = '0x0b'
)
WITH (
    jsonContent VARCHAR(MAX)
) AS rows;


-- 1. Check if the container/folder exists
SELECT *
FROM sys.external_data_sources
WHERE name = 'cosmictracker_storage';

-- 2. List files in the directory (using OPENROWSET with wildcard)
SELECT 
    filename() AS file_name,
    filepath() AS file_path
FROM OPENROWSET(
    BULK 'source/daily/*.json',
    DATA_SOURCE = 'cosmictracker_storage',
    FORMAT = 'CSV',
    FIELDTERMINATOR = '0x0b',
    FIELDQUOTE = '0x0b'
) WITH (dummy VARCHAR(1)) AS files;
